import java.io.IOException;
import javax.servlet.http.*;

public class XSSSafeServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String safeUserInput = sanitizeUserInput(userInput);
        String output = "Welcome, " + safeUserInput + "!";

        response.setContentType("text/html");
        response.setCharacterEncoding("UTF-8");
        response.getWriter().write("<html><body>");
        response.getWriter().write("<h1>" + output + "</h1>");
        response.getWriter().write("</body></html>");
    }

    private String sanitizeUserInput(String userInput) {
        // Implement proper input sanitization and encoding here
        // For example, you can use OWASP Java Encoder library for encoding
        return org.owasp.encoder.Encode.forHtml(userInput);
    }
}

